"""Uvicorn — ASGI server implementation."""
from __future__ import annotations

from typing import Any, Callable, Dict, List, Optional, Tuple, Type, Union


def run(
    app: Union[str, Callable],
    *,
    host: str = "127.0.0.1",
    port: int = 8000,
    uds: Optional[str] = None,
    fd: Optional[int] = None,
    loop: str = "auto",
    http: Union[str, Type] = "auto",
    ws: Union[str, Type] = "auto",
    ws_max_size: int = 16777216,
    ws_ping_interval: Optional[float] = 20.0,
    ws_ping_timeout: Optional[float] = 20.0,
    ws_per_message_deflate: bool = True,
    lifespan: str = "auto",
    interface: str = "auto",
    reload: bool = False,
    reload_dirs: Optional[Union[List[str], str]] = None,
    reload_delay: float = 0.25,
    reload_includes: Optional[List[str]] = None,
    reload_excludes: Optional[List[str]] = None,
    workers: Optional[int] = None,
    env_file: Optional[str] = None,
    log_config: Optional[Union[Dict, str]] = None,
    log_level: Optional[str] = None,
    access_log: bool = True,
    use_colors: Optional[bool] = None,
    proxy_headers: bool = True,
    server_header: bool = True,
    date_header: bool = True,
    forwarded_allow_ips: Optional[Union[List[str], str]] = None,
    root_path: str = "",
    limit_concurrency: Optional[int] = None,
    limit_max_requests: Optional[int] = None,
    backlog: int = 2048,
    timeout_keep_alive: int = 5,
    timeout_notify: int = 30,
    timeout_graceful_shutdown: Optional[int] = None,
    callback_notify: Callable[..., Any] = lambda *a, **kw: None,
    ssl_keyfile: Optional[str] = None,
    ssl_certfile: Optional[str] = None,
    ssl_keyfile_password: Optional[str] = None,
    ssl_version: Optional[int] = None,
    ssl_cert_reqs: Optional[int] = None,
    ssl_ca_certs: Optional[str] = None,
    ssl_ciphers: str = "TLSv1",
    headers: Optional[List[Tuple[str, str]]] = None,
    factory: bool = False,
    h11_max_incomplete_event_size: Optional[int] = None,
) -> None:
    """
    Run an ASGI application with uvicorn.

    Usage::

        import uvicorn
        from myapp import app

        if __name__ == "__main__":
            uvicorn.run(app, host="0.0.0.0", port=8000, reload=True)

    Or from the command line::

        uvicorn myapp:app --host 0.0.0.0 --port 8000 --reload
    """
    from uvicorn.main import Server, Config

    config = Config(
        app=app,
        host=host,
        port=port,
        reload=reload,
        workers=workers,
        log_level=log_level or "info",
        access_log=access_log,
    )
    server = Server(config=config)
    server.run()
